mapper.select:
SELECT id
FROM financial_node_snapshot
WHERE user_id = #{userId}
          AND year = #{year}
          AND month = #{month}
  AND type = 'ASSET'
  AND closed = FALSE

SELECT COALESCE(SUM(amount),0)
FROM flow_snapshot
WHERE user_id = #{userId}
          AND year = #{year}
          AND month = #{month}
  AND to_snapshot_id = #{assetSnapshotId}

mapper.update:
UPDATE financial_node_snapshot
SET current_balance = #{newBalance}
WHERE id = #{assetSnapshotId}

UPDATE financial_node_snapshot
SET closed = TRUE
WHERE user_id = #{userId}
          AND year = #{year}
          AND month = #{month}

mapper.select:
SELECT CASE
           WHEN COUNT(*) > 0 THEN TRUE
           ELSE FALSE
           END
FROM financial_node_snapshot
WHERE user_id = #{userId}
          AND year = #{year}
          AND month = #{month}
  AND closed = TRUE
